import { Outlet, NavLink, useNavigate } from "react-router-dom";

export default function LearnerLayout() {
  const navigate = useNavigate();
  const name = localStorage.getItem("student_name") || "Student";
  const initials = name
    .split(" ")
    .map((w) => w[0])
    .join("")
    .toUpperCase()
    .slice(0, 2);

  const logout = () => {
    localStorage.clear();
    navigate("/");
  };

  return (
    <div style={styles.shell}>
      {/* Sidebar */}
      <aside style={styles.sidebar}>
        <div style={styles.logoWrap}>
          <span style={styles.logo}>Pathrix</span>
        </div>

        <div style={styles.studentWrap}>
          <div style={styles.avatar}>{initials}</div>
          <div>
            <div style={styles.studentName}>{name}</div>
            <div style={styles.badge}>Beginner</div>
          </div>
        </div>

        <div style={styles.masteryWrap}>
          <div style={styles.masteryLabel}>
            <span>Overall mastery</span>
            <span>0%</span>
          </div>
          <div style={styles.masteryTrack}>
            <div style={{ ...styles.masteryFill, width: "0%" }} />
          </div>
        </div>

        <nav style={styles.nav}>
          <NavItem to="/dashboard" label="Dashboard" icon="⊞" />
          <NavItem to="/dashboard/learn" label="Learn" icon="📖" />
          <NavItem to="/dashboard/quiz" label="Quiz" icon="✏️" />
          <NavItem to="/dashboard/path" label="My Path" icon="🗺️" />
        </nav>

        <div style={styles.bottom}>
          <button style={styles.logoutBtn} onClick={logout}>
            ← Logout
          </button>
        </div>
      </aside>

      {/* Main content */}
      <main style={styles.main}>
        <Outlet />
      </main>
    </div>
  );
}

function NavItem({ to, label, icon }) {
  return (
    <NavLink
      to={to}
      end={to === "/dashboard"}
      style={({ isActive }) => ({
        ...styles.navItem,
        background: isActive ? "#E1F5EE" : "transparent",
        color: isActive ? "#085041" : "#888780",
        fontWeight: isActive ? 600 : 400,
      })}
    >
      <span style={styles.navIcon}>{icon}</span>
      {label}
    </NavLink>
  );
}

const styles = {
  shell: {
    display: "flex",
    minHeight: "100vh",
    fontFamily: "'Sora', sans-serif",
  },
  sidebar: {
    width: "220px",
    minHeight: "100vh",
    background: "#fff",
    borderRight: "1.5px solid #F1EFE8",
    display: "flex",
    flexDirection: "column",
    padding: "0 0 24px 0",
    flexShrink: 0,
  },
  logoWrap: {
    padding: "24px 20px 20px",
    borderBottom: "1.5px solid #F1EFE8",
  },
  logo: {
    fontSize: "1.3rem",
    fontWeight: 600,
    color: "#1D9E75",
    letterSpacing: "-0.5px",
  },
  studentWrap: {
    display: "flex",
    alignItems: "center",
    gap: "12px",
    padding: "20px 20px 16px",
  },
  avatar: {
    width: "38px",
    height: "38px",
    borderRadius: "50%",
    background: "#1D9E75",
    color: "#fff",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontSize: "0.85rem",
    fontWeight: 600,
    flexShrink: 0,
  },
  studentName: {
    fontSize: "0.85rem",
    fontWeight: 600,
    color: "#444441",
    marginBottom: "3px",
  },
  badge: {
    fontSize: "0.72rem",
    color: "#1D9E75",
    background: "#E1F5EE",
    padding: "2px 8px",
    borderRadius: "20px",
    display: "inline-block",
    fontWeight: 500,
  },
  masteryWrap: {
    padding: "0 20px 20px",
    borderBottom: "1.5px solid #F1EFE8",
  },
  masteryLabel: {
    display: "flex",
    justifyContent: "space-between",
    fontSize: "0.75rem",
    color: "#888780",
    marginBottom: "6px",
  },
  masteryTrack: {
    height: "6px",
    background: "#F1EFE8",
    borderRadius: "10px",
    overflow: "hidden",
  },
  masteryFill: {
    height: "100%",
    background: "#1D9E75",
    borderRadius: "10px",
    transition: "width 0.4s ease",
  },
  nav: {
    display: "flex",
    flexDirection: "column",
    padding: "16px 12px",
    gap: "4px",
    flex: 1,
  },
  navItem: {
    display: "flex",
    alignItems: "center",
    gap: "10px",
    padding: "10px 12px",
    borderRadius: "8px",
    fontSize: "0.88rem",
    textDecoration: "none",
    transition: "background 0.15s",
  },
  navIcon: {
    fontSize: "1rem",
  },
  bottom: {
    padding: "0 20px",
  },
  logoutBtn: {
    width: "100%",
    padding: "10px",
    borderRadius: "8px",
    background: "transparent",
    border: "1.5px solid #F1EFE8",
    color: "#888780",
    fontSize: "0.85rem",
    cursor: "pointer",
  },
};
